previewCss:
.darma-loader-darma-custom-664 {color: var(--loader-color, #f97316);
  --loader-secondary-color: var(--loader-secondary-color, #facc15);

  position: relative;
  width: 160px;
  height: 160px;
  border: 4px solid #282828;
  overflow: hidden;
  border-radius: 50%;
  box-shadow: -5px -5px 5px color-mix(in srgb, var(--loader-bg, #111827) 15%, transparent),
    10px 10px 10px color-mix(in srgb, var(--loader-color, #f97316) 45%, transparent),
    inset -5px -5px 5px color-mix(in srgb, var(--loader-bg, #111827) 25%, transparent),
    inset 10px 10px 10px color-mix(in srgb, var(--loader-color, #f97316) 45%, transparent);
}

.darma-loader-darma-custom-664:before {
  content: "";
  position: absolute;
  top: 25px;
  left: 25px;
  right: 25px;
  bottom: 25px;
  z-index: 10;
  background: #212121;
  border-radius: 50%;
  border: 2px solid #292929;
  box-shadow: inset -2px -2px 5px color-mix(in srgb, var(--loader-bg, #111827) 25%, transparent),
    inset 3px 3px 5px color-mix(in srgb, var(--loader-color, #f97316) 45%, transparent);
}

.darma-loader-darma-custom-664 span {
  position: absolute;
  width: 100%;
  height: 100%;
  border-radius: 50%;
  background-image: linear-gradient(
    -225deg,
    #ff7402 0%,
    #ffe700 50%,
    #fff55e 100%
  );
  filter: blur(20px);
  z-index: -1;
  animation: darma-loader-darma-custom-664-animate 0.5s linear infinite;
}

@keyframes darma-loader-darma-custom-664-animate {
  0% {
    transform: rotate(0deg);
  }

  100% {
    transform: rotate(360deg);
  }
}

